const AWS = require('aws-sdk');
const { v4: uuidv4 } = require('uuid');

const sqs = new AWS.SQS({ apiVersion: '2012-11-05' });
const dynamodb = new AWS.DynamoDB.DocumentClient();
const https = require('https');

const PAYMENT_API_URL = process.env.PAYMENT_API_URL;
const PAYMENT_API_KEY = process.env.PAYMENT_API_KEY;
const TABLE_NAME = process.env.TABLE_NAME;

exports.handler = async (event) => {
  for (const record of event.Records) {
    try {
      const order = JSON.parse(record.body);
      
      // Validate input
      if (!order.orderId || !order.amount || !order.customerId) {
        console.error('Invalid order data', order);
        continue;
      }

      // Process payment
      const paymentResult = await processPayment(order);
      
      // Update DynamoDB
      await updateOrderStatus(order.orderId, paymentResult);
      
    } catch (error) {
      console.error('Error processing order:', error);
      // Continue processing other orders
    }
  }
  
  return { statusCode: 200, body: 'Processed' };
};

async function processPayment(order) {
  return new Promise((resolve, reject) => {
    const postData = JSON.stringify({
      amount: order.amount,
      customerId: order.customerId,
      orderId: order.orderId
    });

    const options = {
      hostname: new URL(PAYMENT_API_URL).hostname,
      port: 443,
      path: new URL(PAYMENT_API_URL).pathname,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(postData),
        'Authorization': `Bearer ${PAYMENT_API_KEY}`
      }
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => {
        data += chunk;
      });
      res.on('end', () => {
        try {
          const result = JSON.parse(data);
          resolve(result);
        } catch (e) {
          reject(e);
        }
      });
    });

    req.on('error', reject);
    req.write(postData);
    req.end();
  });
}

async function updateOrderStatus(orderId, paymentResult) {
  const params = {
    TableName: TABLE_NAME,
    Key: { orderId },
    UpdateExpression: 'SET #status = :status, #paymentId = :paymentId, #updatedAt = :updatedAt',
    ExpressionAttributeNames: {
      '#status': 'status',
      '#paymentId': 'paymentId',
      '#updatedAt': 'updatedAt'
    },
    ExpressionAttributeValues: {
      ':status': paymentResult.status || 'failed',
      ':paymentId': paymentResult.paymentId || null,
      ':updatedAt': new Date().toISOString()
    }
  };

  await dynamodb.update(params).promise();
}